import { useState, useEffect, useRef } from "react";

const useReveal = (opts = {}) => {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const ob = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) { setVis(true); ob.unobserve(el); }
    }, { threshold: opts.t || 0.15 });
    ob.observe(el);
    return () => ob.disconnect();
  }, []);
  return [ref, vis];
};

const useCount = (end, active, dur = 2200) => {
  const [v, setV] = useState(0);
  const f = useRef(null);
  useEffect(() => {
    if (!active) return;
    const s = performance.now();
    const tick = (n) => {
      const p = Math.min((n - s) / dur, 1);
      setV(Math.floor((1 - Math.pow(1 - p, 4)) * end));
      if (p < 1) f.current = requestAnimationFrame(tick);
    };
    f.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(f.current);
  }, [active, end, dur]);
  return v;
};

const Stars = ({ count = 40, color = "rgba(201,168,76,0.15)" }) => {
  const s = useRef(Array.from({ length: count }, () => ({
    x: Math.random() * 100, y: Math.random() * 100,
    sz: Math.random() * 2 + 0.5, o: Math.random() * 0.4 + 0.1, d: Math.random() * 4 + 2,
  }))).current;
  return (
    <div style={{ position: "absolute", inset: 0, overflow: "hidden", pointerEvents: "none" }}>
      {s.map((st, i) => (
        <div key={i} style={{
          position: "absolute", left: `${st.x}%`, top: `${st.y}%`,
          width: st.sz, height: st.sz, borderRadius: "50%", background: color, opacity: st.o,
          animation: `twinkle ${st.d}s ease-in-out infinite`, animationDelay: `${-st.d * Math.random()}s`
        }} />
      ))}
    </div>
  );
};

